#include <stdio.h>
#include <math.h>
int main() {
    long long n, m, x;
    while (scanf("%lld %lld %lld", &n, &m, &x) == 3 && (n != 0 || m != 0 || x != 0)) {
        long long total_cost = 0;
        for (long long i = 1; i <= m; i++) {
            long long t = x + (i - 1) * n;
            long long cost = floor((t - n) / (double)m);
            if (cost < 0) cost = 0;
            total_cost += cost;
        }
        printf("%lld\n", total_cost);
    }
    return 0;
}

